ALTER TABLE content_fields MODIFY COLUMN position BIGINT NOT NULL, ADD COLUMN active_parent_id VARCHAR(36) GENERATED ALWAYS AS (IF(status = 'active', COALESCE(parent_id, _utf8mb4''), NULL)) STORED, ADD COLUMN active_position BIGINT GENERATED ALWAYS AS (IF(status = 'active', position, NULL)) STORED, ADD UNIQUE KEY uq_content_fields_active_sibling_position (model_id, active_parent_id, active_position);
